const workbook = new Excel.Workbook()
await workbook.xlsx.readFile(filePath)
const worksheet = workbook.getWorksheet(1) // or workbook.eachSheet

worksheet.getRow(1).protection = { locked: false };
worksheet.getColumn(1).protection = { locked: false };
worksheet.getCell('B2').protection = { locked: false };

await worksheet.protect('password')

await workbook.xlsx.writeFile(xlsxFilePath)
